// Promise<string> represents a future string value
const promise = new Promise<string>((resolve) => {
  // resolve is called when the async work completes
  resolve('Data loaded');
});

// .then receives the resolved value once it's available
const promise = Promise.resolve('Hello');

promise.then((value: string) => {
  console.log(value);        // 'Hello'
  console.log(value.length); // 5 -- fully typed as string
});

// async makes the function ALWAYS return a Promise
async function fetchUser(id: number): Promise<string> {
  // Simulate a network request
  return 'User data for ' + id; // wrapped in Promise automatically
}

// await unpacks the Promise value (only works inside async functions)
async function loadData(): Promise<void> {
  const data = await fetchUser(1);
  // Execution pauses here until fetchUser resolves
  console.log(data); // 'User data for 1'
}

// try/catch works the same as in synchronous code
async function safeLoad(): Promise<void> {
  try {
    const data = await fetchUser(1);
    console.log(data);
  } catch (error) {
    console.error('Failed to load:', error);
  }
}

// Promise.all waits for ALL promises -- they run concurrently
async function loadAll(): Promise<void> {
  const [user, posts] = await Promise.all([
    fetchUser(1),
    fetchPosts(1)
  ]);
  // Both requests happen in parallel -- faster than sequential
  console.log(user, posts);
}
